 1→import { useNavigate } from 'react-router-dom';
 2→import { useAuth } from '../../Context/useAuth';
 3→import './MentionText.css';
 4→
 5→const MENTION_SPLIT_REGEX = /(@[\w-]+)/g;
 6→const MENTION_EXTRACT_REGEX = /^@([\w-]+)$/;
 7→
 8→export default function MentionText({ text }) {
 9→    const navigate = useNavigate();
10→    const { user } = useAuth();
11→    const currentUsername = user?.userData?.[0]?.username;
12→
13→    if (!text) return null;
14→
15→    const parts = text.split(MENTION_SPLIT_REGEX);
16→
17→    return (
18→        <>
19→            {parts.map((part, i) => {
20→                const match = part.match(MENTION_EXTRACT_REGEX);
21→                if (!match) return part;
22→
23→                const username = match[1];
24→                return (
25→                    <span
26→                        key={i}
27→                        className="mention-link"
28→                        onClick={(e) => {
29→                            e.stopPropagation();
30→                            if (username === currentUsername) {
31→                                navigate('/profile');
32→                            } else {
33→                                navigate(`/u/${username}`);
34→                            }
35→                        }}
36→                    >
37→                        {part}
38→                    </span>
39→                );
40→            })}
41→        </>
42→    );
43→}
