file.content:
.opinions-loading-container{
    display: flex;
    width: 100%;
    height: 100%;
    justify-content: center;
    align-items: center;
}
.side-bar-opinions-parent-container{
    display: flex;
    justify-content: flex-start;
    flex-direction: column;
    align-items: center;
    width: 98%;
    height: 100%;
    gap: 0.8rem;
}
.signal-container{
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: flex-start;
    height: fit-content;
    width: 90%;
    margin-top: 1rem;
    padding: 0.8rem;
    border: 0.7px solid  rgba(151, 151, 151, 0.168);
    gap: 0.8rem;
    background-color: #D4A853;
    border-radius: 15px;
}
.signal-header{
    font-weight: 780;
    font-size: 1.1rem;
    line-height: 1.4rem;
    padding: 0;
    margin: 0;
}
.write-opinions-bttn {
  cursor: pointer;
  border: none;
  padding: 0.5rem 0.8rem;
  color: rgb(255, 255, 255);
  font-weight: 650;
  border-radius: 15px;
  background-color: rgb(4, 20, 29); 
  transition: ease-in-out 0.2s;
}
.write-opinions-bttn:hover{
    background-color: #B8862D;
}

.latest-opinions-container{
    display: flex;
    flex-direction: column;
    align-items: flex-start;
    justify-content: flex-start;
    width: 90%;
    padding: 0.8rem;
    border: 0.7px solid  rgba(151, 151, 151, 0.168);
    gap: 0.8rem;
    height: 480px;
    overflow-x: hidden;
    overflow-y: auto;
}
.latest-opinions-container::-webkit-scrollbar{
    width: 5px;
}
.latest-opinions-container::-webkit-scrollbar-thumb{
    background: var(--accent-amber);
    border-radius: 4px;
}
.latest-opinions-container::-webkit-scrollbar-track{
    background-color: var(--bg-pill);
}

.latest-opinions-header{
    font-weight: 780;
    font-family: var(--font-ui);
    color: var(--text-heading);
}

/* ── Opinion Editor (oe-) ── */
.oe-backdrop {
    display: flex;
    justify-content: center;
    align-items: center;
    position: fixed;
    inset: 0;
    background-color: rgba(0, 0, 0, 0.25);
    backdrop-filter: blur(12px);
    z-index: 130;
}

.oe-card {
    position: relative;
    display: flex;
    flex-direction: column;
    width: min(480px, 90%);
    background-color: var(--bg-card);
    border: 1px solid var(--border-card);
    border-radius: 12px;
    overflow: hidden;
    box-shadow: 0 8px 30px rgba(0, 0, 0, 0.12);
    transition: box-shadow 0.25s ease;
}

.oe-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.85rem 1.15rem;
    border-bottom: 1px solid var(--border-card);
}
.oe-title {
    margin: 0;
    padding: 0;
    font-family: var(--font-ui);
    font-size: 0.88rem;
    font-weight: 650;
    color: var(--text-heading);
    letter-spacing: -0.01rem;
}
.oe-close-btn {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 28px;
    height: 28px;
    padding: 0;
    border: none;
    background: none;
    border-radius: 50%;
    color: var(--text-faint);
    cursor: pointer;
    transition: background-color 0.15s ease, color 0.15s ease;
}
.oe-close-btn:hover {
    background-color: var(--bg-pill);
    color: var(--text-heading);
}

.oe-body {
    padding: 0.75rem 1.15rem;
}
.oe-textarea {
    width: 100%;
    min-height: 120px;
    border: none;
    background-color: transparent;
    color: var(--text-body);
    font-family: var(--font-serif);
    font-size: 0.92rem;
    line-height: 1.7;
    letter-spacing: 0.005rem;
    resize: none;
    padding: 0;
    box-sizing: border-box;
}
.oe-textarea::placeholder {
    color: var(--text-faint);
}
.oe-textarea:focus {
    outline: none;
}

.oe-footer {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.6rem 1.15rem 0.85rem 1.15rem;
    border-top: 1px solid var(--border-card);
}
.oe-char-count {
    font-family: var(--font-ui);
    font-size: 0.7rem;
    font-weight: 500;
    color: var(--text-faint);
    letter-spacing: 0.01rem;
    transition: color 0.15s ease;
}
.oe-char-warn {
    color: var(--accent-amber, #f59e0b);
}
.oe-char-limit {
    color: rgb(255, 116, 116);
}

.oe-save-btn {
    border: none;
    padding: 0.35rem 1.15rem;
    border-radius: 20px;
    background-color: var(--accent-amber);
    color: #ffffff;
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    cursor: pointer;
    transition: opacity 0.15s ease, transform 0.1s ease;
}
.oe-save-btn:hover {
    opacity: 0.88;
}
.oe-save-btn:active {
    transform: scale(0.97);
}
.oe-save-disabled {
    cursor: default;
    user-select: none;
    opacity: 0.4;
}
.oe-save-disabled:hover {
    opacity: 0.4;
}

.oe-loader {
    position: absolute;
    bottom: 0;
    left: 0;
    width: 100%;
    height: 3px;
    overflow: hidden;
    border-radius: 0 0 12px 12px;
}

.sidebar-opinions-cards-container{
    display: flex;
    flex-direction: column;
    width: 100%;
    height: fit-content;
    gap: 0.55rem;
}

.opinions-card-container{
    display: flex;
    flex-direction: column;
    width: 95%;
    height: 80vh;
    align-items: flex-start;
    justify-content: flex-start;
    gap: 0.5rem;
    position: relative;
    top: 130px;
    padding-bottom: 8rem;
}
.opinions-card{
    display: flex;
    flex-direction: column;
    width: 95%;
    height: fit-content;
    gap: 1rem;
}

.opinions-profile{
    width: 30px;
    height: 30px;
    object-fit: cover;
    border-radius: 50%;
    cursor: pointer;
}
.opinions-username{
    font-weight: 780;
    margin: 0;
    padding: 0;
    cursor: pointer;
}
.opinions-username:hover{
    text-decoration: underline;
}
.opinions-user-email{
    padding: 0;
    margin: 0;
    font-size: 1rem;
    font-weight: 560;
    color: rgb(117, 127, 132);
}
.opinions-user-metadata{
    display: flex;
    justify-content: flex-start;
    align-items: center;
    gap: 0.5rem;
}
.opinion-username{
    font-weight: 680;
    margin: 0;
    padding: 0;
}
.opinions-page-content{
    display: flex;
    width: fit-content;
    height: fit-content;
    justify-content: center;
    align-items: center;
    position: relative;
    font-weight: 400;
    color: rgb(80, 80, 80);
    line-height: 1.2rem;
    font-size: 0.8rem;
    border-radius: 15px;
    padding: 0.8rem;
    background-color: rgba(212, 168, 83, 0.1);
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05),
                0 1px 4px rgba(0, 0, 0, 0.05);
}
/* The larger circle */
.opinions-page-content::before {
    content: "";
    position: absolute;
    bottom: -15px; /* Position below */
    left: 30px;
    width: 12px;
    height: 12px;
    border-radius: 50%;
    background-color: rgba(212, 168, 83, 0.25);
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05);
}
/* The smaller circle */
.opinions-page-content::after {
    content: "";
    position: absolute;
    bottom: -20px; /* Position further below */
    left: 20px;
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background-color: rgba(212, 168, 83, 0.2);
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05);
}
.opinion-reply-button{
    position: absolute;
    bottom: -25px;
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.2rem 0.5rem;
    border-radius: 10px;
    background-color: rgba(212, 168, 83, 0.25);
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05),
                0 1px 4px rgba(0, 0, 0, 0.05);
    gap: 0.2rem;
    color: rgb(80, 80, 80);
}
.mobile-write-opinions{
    display: flex;
    position: fixed;
    width: 100%;
    height: 120px;
    gap: 0.5rem;
    border-bottom: 0.7px solid #0000001b;
    background-color: #ffffff;
    z-index: 131;

}
.write-profile-container{
    display: flex;
    justify-content: flex-start;
    align-items: flex-start;
    width: fit-content;
    height: 100%;
    padding: 0rem 0 0 0.2rem;
}
.write-profile{
    width: 45px;
    height: 45px;
    border-radius: 50%;
    object-fit: cover;
}
.opinion-input-container{
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: flex-end;
    width: 100%;
    height: 100%;
}
.mobile-input-opinion{
    width: 95%;
    height: 80%;
    padding: 0.4rem;
    border: none;
    background-color: rgb(255, 255, 255);
    color: #000000;
    font-family: "Nunito", sans-serif;
    font-size: 1.2rem;
}
.mobile-input-opinion:focus{
    outline: none;
}

.my-opinions-content{
    position: relative;
    margin: 0;
    font-weight: 400;
    color: rgb(80, 80, 80);
    line-height: 1.2rem;
    font-size: 0.8rem;
    border-radius: 15px;
    padding: 0.8rem 1rem;
    background-color: rgba(212, 168, 83, 0.1);
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05);
}

.see-fullpage-bttn{
    cursor: pointer;
    font-weight: 650;
    font-size: 0.78rem;
    color: var(--accent-amber);
    font-family: var(--font-ui);
    text-decoration: underline;
}

/* ── Write Opinion FAB ── */
.write-opinion-fab {
    position: fixed;
    right: 1.25rem;
    bottom: 6.5rem;
    z-index: 10;
    display: flex;
    justify-content: center;
    align-items: center;
    width: 54px;
    height: 54px;
    background-color: #1a1a1a;
    border: none;
    border-radius: 50%;
    color: #ffffff;
    cursor: pointer;
    box-shadow: 0 6px 24px rgba(0, 0, 0, 0.18),
                0 1.5px 6px rgba(0, 0, 0, 0.10),
                0 0 18px rgba(212, 168, 83, 0.18);
    transition: box-shadow 0.25s ease,
                transform 0.25s ease;
    user-select: none;
    -webkit-tap-highlight-color: transparent;
}
.write-opinion-fab:hover {
    box-shadow: 0 8px 30px rgba(0, 0, 0, 0.24),
                0 2px 8px rgba(0, 0, 0, 0.12),
                0 0 22px rgba(212, 168, 83, 0.24);
    transform: translateY(-2px);
}
.write-opinion-fab:active {
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.14);
}

.opinion-fab-icon-wrapper {
    display: flex;
    justify-content: center;
    align-items: center;
    flex-shrink: 0;
    width: 24px;
    height: 24px;
    color: #ffffff;
}
.opinion-fab-icon-wrapper svg {
    display: block;
}
.opinions-page-parent-container{
    display: flex;
    flex-direction: column;
    justify-content: flex-start;
    align-items: center;
    position: relative;
    width: 100%;
    top: 60px;
    height: 100dvh;
    gap: 0.5rem;
    padding: 1rem 0 0rem 0;
}
.opinions-page-no-opinions{
    display: flex;
    width: 100%;
    height: 100%;
    justify-content: center;
    align-items: center;
}
.icon-glyph{
    padding: 0.5rem;
}
.is-sending-opinion-container{
    display: flex;
    justify-content: center;
    align-items: center;
    width: 98%;
    height: 100%;
    z-index: 130;
    background-color: rgba(255, 255, 255, 0.089);
    backdrop-filter: blur(25px);
}
.opinions-in-view{
    display: flex;
    justify-content: center;
    align-items: center;
    height: 400px;
    width: 100%;
    padding: 2rem 0;
}

.visited-profile-opinions-container{
    display: flex;
    justify-content: flex-start;
    gap: 1rem;
    flex-wrap: wrap;
    width: 90%;
    padding: 1rem;
    height: fit-content;
    margin-top: 1rem;
    background-color: rgba(255, 255, 255, 0.23);
    backdrop-filter: blur(25px);
    border-radius: 20px;
    border: 0.7px solid rgba(151, 151, 151, 0.168);
    margin-bottom: 4rem;
}

.visited-profile-opinion-card{
    display: flex;
    flex-direction: column;
    width: 100%;
    height: fit-content;
    gap: 1rem;
}

.visited-profile-opinion-content{
    display: flex;
    width: fit-content;
    height: fit-content;
    justify-content: center;
    align-items: center;
    position: relative;
    font-weight: 500;
    color: rgb(80, 80, 80);
    line-height: 1.2rem;
    font-size: 1rem;
    border-radius: 15px;
    padding: 0.8rem;
    background-color: rgba(212, 168, 83, 0.1);
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05),
                0 1px 4px rgba(0, 0, 0, 0.05);
}

/* The larger circle */
.visited-profile-opinion-content::before {
    content: "";
    position: absolute;
    bottom: -15px; /* Position below */
    left: 30px;
    width: 12px;
    height: 12px;
    border-radius: 50%;
    background-color: rgba(212, 168, 83, 0.15);
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05);
}
/* The smaller circle */
.visited-profile-opinion-content::after {
    content: "";
    position: absolute;
    bottom: -20px; /* Position further below */
    left: 20px;
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background-color: rgba(212, 168, 83, 0.12);
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05);
}
.visited-user-opinions-inview{
    display: flex;
    justify-content: center;
    align-items: center;
    width: 100%;
