 14→const OpinionViewer = () => {
 15→    const queryClient = useQueryClient();
 16→    const location = useLocation();
 17→    const { opinionId, userId } = location.state;
 18→    const { user, session } = useAuth();
 19→    const textAreaRef = useRef(null);
 20→
 21→    const [replyOpinion, setReplyOpinion] = useState('');
 22→    const [isTyping, setIsTyping] = useState(false);
 23→
 24→    const { textareaProps: mentionTextareaProps, dropdownProps: mentionDropdownProps } = useTextareaMention(replyOpinion, setReplyOpinion, textAreaRef, 280, user?.userData?.[0]?.id);
 25→
 26→    const { data, isLoading } = useQuery({
 27→        queryKey: ['getViewOpinion', opinionId, userId],
 28→        queryFn: ({ queryKey }) => getViewOpinion(queryKey[1], queryKey[2]),
 29→        staleTime: 1000 * 60 * 60,
 30→        gcTime: 1000 * 60 * 60,
 31→        enabled: !!opinionId && !!userId,
 32→        refetchOnWindowFocus: false
 33→    });
 34→
 35→    const cancelTyping = () => {
 36→        setIsTyping(false);
 37→        setReplyOpinion('');
 38→        if (textAreaRef.current) {
 39→            textAreaRef.current.blur();
 40→        }
 41→    };
 42→
 43→    const submitReply = async (receiverId, senderId, parentId) => {
 44→        const formData = new FormData();
 45→        formData.append('opinion', replyOpinion);
 46→
 47→        try {
 48→            await addReplyOpinion(formData, receiverId, senderId, parentId, session?.access_token);
 49→            setReplyOpinion('');
 50→            queryClient.invalidateQueries({ queryKey: ['getViewOpinion', opinionId, userId] });
 51→            queryClient.invalidateQueries({ queryKey: ['getReplyOpinion', opinionId] });
 52→            queryClient.invalidateQueries({ queryKey: ['getOpinions'] });
 53→        } catch (error) {
 54→            console.error(error);
 55→            setReplyOpinion('');
 56→            queryClient.invalidateQueries({ queryKey: ['getViewOpinion', opinionId, userId] });
 57→            queryClient.invalidateQueries({ queryKey: ['getReplyOpinion', opinionId] });
 58→            queryClient.invalidateQueries({ queryKey: ['getOpinions'] });
 59→        }
 60→    };
 61→
 62→    const opinionData = data?.data;
 63→
 64→    // console.log(opinionData)
 65→
 66→    return (
 67→        <>
 68→            {opinionData?.map((opinion) => (
 69→                <motion.div
 70→                    className="so-card-wrapper"
