 42→    const handleSubmitReplyOpinion = async (reply, receiver_id, sender_id, parent_id) => {
 43→        try {
 44→            const formadata = new FormData();
 45→            formadata.append('opinion', reply);
 46→            await addReplyOpinion(formadata, receiver_id, sender_id, parent_id, session?.access_token);
 47→            queryClient.invalidateQueries({ queryKey: ['getReplyOpinion', opinionId] });
 48→            queryClient.invalidateQueries({ queryKey: ['getOpinions'] });
 49→            queryClient.invalidateQueries({ queryKey: ['getViewOpinion'] });
 50→            setReplyOpinion('');
 51→        } catch (error) {
 52→            console.error(error);
 53→            setReplyOpinion('');
 54→            queryClient.invalidateQueries({ queryKey: ['getReplyOpinion', opinionId] });
 55→            queryClient.invalidateQueries({ queryKey: ['getOpinions'] });
 56→            queryClient.invalidateQueries({ queryKey: ['getViewOpinion'] });
 57→        }
 58→    };
 59→
 60→    const cancelTyping = () => {
 61→        setIsTypingId('');
 62→        setReplyOpinion('');
 63→        if (textAreaRef.current) {
 64→            textAreaRef.current.blur();
 65→        }
 66→        setShowReplyButtonId('');
 67→    };
 68→
 69→    const visualDepth = Math.min(depth, MAX_VISUAL_DEPTH);
 70→    const opinioData = data?.pages.flatMap((page) => page.data) || [];
 71→
 72→    return (
 73→        <div
 74→            className="rc-thread"
 75→            style={{ '--depth': visualDepth }}
 76→        >
 77→            {opinioData?.map((opinion, index) => (
 78→                <motion.div
 79→                    className="so-card-wrapper rc-card"
 80→                    key={opinion.id}
 81→                    initial={{ opacity: 0, y: 6 }}
 82→                    animate={{ opacity: 1, y: 0 }}
 83→                    transition={{ duration: 0.25, delay: index * 0.03, ease: "easeOut" }}
 84→                >
 85→                    {depth > 0 && <div className="rc-thread-line" />}
 86→
 87→                    <div className="so-card so-card--flat">
 88→                        <div className="so-card-content">
 89→                            <div className="so-user-row">
 90→                                <div className="so-user-meta">
 91→                                    <div className={`so-avatar-outer ${opinion.users?.badge === 'legend' ? 'avatar-ring-legend' : opinion.users?.badge === 'og' ? 'avatar-ring-og' : ''}`}>
 92→                                        <img
 93→                                            className="so-avatar"
 94→                                            src={opinion.users?.image_url || '../assets/profile.jpg'}
 95→                                            alt={`${opinion?.users?.name || "User"} profile picture`}
 96→                                        />
 97→                                    </div>
 98→                                    <div className="so-name-block">
 99→                                        <div className="so-name-line">
100→                                            <span className="so-username">{opinion.users?.name}</span>
101→                                            <VerifiedBadge badge={opinion.users?.badge} size={14}/>
102→                                        </div>
103→                                        <span className="so-handle">{formatPostDate(opinion.created_at)}</span>
104→                                    </div>
105→                                </div>
106→                            </div>
107→
108→                            <div className="so-body">
109→                                <MentionText text={opinion.opinion} />
110→                            </div>
111→
112→                            <div className="so-meta-bar">
113→                                {opinion.reply_count > 0 && (
114→                                    <span
115→                                        className="so-reply-pill"
116→                                        onClick={() => setShowReply(prev => !prev)}
117→                                    >
118→                                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
119→                                            <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
120→                                        </svg>
121→                                        {showReply ? 'Hide' : 'Show'} {opinion.reply_count} {opinion.reply_count === 1 ? 'reply' : 'replies'}
122→                                    </span>
123→                                )}
124→                                <span
125→                                    className="so-reply-pill"
126→                                    onClick={() => setShowReplyButtonId(
127→                                        showReplyButtonId === opinion.id ? '' : opinion.id
128→                                    )}
129→                                >
130→                                    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
131→                                        <polyline points="9 17 4 12 9 7" />
132→                                        <path d="M20 18v-2a4 4 0 0 0-4-4H4" />
133→                                    </svg>
134→                                    Reply
135→                                </span>
136→                            </div>
137→
138→                            <AnimatePresence>
139→                                {showReplyButtonId === opinion.id && (
140→                                    <motion.div
141→                                        initial={{ height: 0, opacity: 0 }}
142→                                        animate={{ height: "auto", opacity: 1 }}
143→                                        exit={{ height: 0, opacity: 0 }}
144→                                        transition={{ duration: 0.2 }}
145→                                        className="rc-reply-input-wrapper"
146→                                    >
147→                                        <textarea
148→                                            ref={textAreaRef}
149→                                            maxLength={280}
150→                                            value={replyOpinion}
151→                                            onChange={(e) => { setReplyOpinion(e.target.value); mentionTextareaProps.onChange(e); }}
152→                                            onKeyDown={mentionTextareaProps.onKeyDown}
153→                                            onKeyUp={mentionTextareaProps.onKeyUp}
154→                                            onFocus={() => setIsTypingId(opinion.id)}
155→                                            className="ov-reply-input"
156→                                            placeholder={`Add a reply to '${opinion.users?.name}'`}
157→                                            rows={2}
158→                                        />
159→                                        <MentionDropdown {...mentionDropdownProps} />
160→
161→                                        {isTypingId === opinion.id && (
162→                                            <div className="ov-btn-row">
163→                                                <button onClick={cancelTyping} className="ov-btn-cancel">Cancel</button>
164→                                                <button
165→                                                    disabled={replyOpinion.trim().length === 0}
166→                                                    onClick={() => handleSubmitReplyOpinion(replyOpinion, opinion.users.id, user?.userData[0].id, opinion.id)}
167→                                                    className={`ov-btn-submit ${replyOpinion.trim().length === 0 ? 'ov-btn-disabled' : ''}`}
168→                                                >
169→                                                    Submit
170→                                                </button>
171→                                            </div>
172→                                        )}
173→                                    </motion.div>
174→                                )}
175→                            </AnimatePresence>
176→
177→                            <AnimatePresence>
178→                                {showReply && (
179→                                    <motion.div
180→                                        initial={{ opacity: 0 }}
181→                                        animate={{ opacity: 1 }}
182→                                        exit={{ opacity: 0 }}
183→                                        transition={{ duration: 0.2 }}
184→                                    >
185→                                        <OpinionsReplyCard opinionId={opinion.id} depth={depth + 1} />
186→                                    </motion.div>
187→                                )}
188→                            </AnimatePresence>
189→                        </div>
190→                    </div>
191→                </motion.div>
192→            ))}
193→
194→            {hasNextPage && (
195→                <button className="rc-load-more" onClick={() => fetchNextPage()}>
196→                    {isFetchingNextPage ? 'Loading...' : 'Show more replies'}
197→                </button>
198→            )}
199→        </div>
200→    );
201→};
202→
203→export default OpinionsReplyCard;
