  6→import { motion, AnimatePresence } from "framer-motion";
  7→import useTextareaMention from "../mentions/useTextareaMention";
  8→import MentionDropdown from "../mentions/MentionDropdown";
  9→
 10→const OpinionEditor = ({onClose}) =>{
 11→    const [opinion, setOpinion] = useState('');
 12→    const {session, user} = useAuth();
 13→    const [isSaving, setIsSaving] = useState(false);
 14→    const opinionTextareaRef = useRef(null);
 15→
 16→    const { textareaProps: mentionTextareaProps, dropdownProps: mentionDropdownProps } = useTextareaMention(opinion, setOpinion, opinionTextareaRef, 280, user?.userData?.[0]?.id);
 17→
 18→    const queryClient = useQueryClient();
 19→
 20→    const handleCloseEditor = () =>{
 21→        onClose();
 22→    }
 23→
 24→    const handleClickSave = async(e) =>{
 25→        e.stopPropagation();
 26→        if(isSaving){
 27→            return;
 28→        }
 29→        const formdata = new FormData();
 30→        formdata.append('opinion', opinion)
 31→
 32→        try {
 33→            setIsSaving(true);
 34→
 35→            const message = await addOpinion(formdata, session?.access_token);
 36→            if(message){
 37→                // console.log(message)
 38→            }
 39→            setIsSaving(false)
 40→            queryClient.invalidateQueries({ queryKey: ['getOpinions'] });
 41→            queryClient.invalidateQueries({ queryKey: ['getMyOpinions'] });
 42→        } catch (error) {
 43→            setIsSaving(false)
 44→            setOpinion('')
 45→            throw new Error('error uploading data')
 46→        } finally {
 47→            setOpinion('')
 48→            onClose();
 49→        }
 50→
 51→    }
 52→
 53→    const charCount = opinion.length;
 54→    const isNearLimit = charCount > 259;
 55→    const isAtLimit = charCount > 279;
 56→
 57→    return(
 58→        <AnimatePresence>
 59→        <motion.div
 60→            className="oe-backdrop"
 61→            initial={{opacity: 0}}
 62→            animate={{opacity: 1}}
 63→            exit={{opacity: 0}}
 64→            transition={{duration: 0.2}}
 65→            onClick={handleCloseEditor}
 66→        >
 67→            <motion.div
 68→                className="oe-card"
 69→                initial={{opacity: 0, scale: 0.95, y: 12}}
 70→                animate={{opacity: 1, scale: 1, y: 0, transition: {type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
 71→                exit={{opacity: 0, scale: 0.95, y: 12, transition: {duration: 0.15, ease: 'easeOut'}}}
 72→                onClick={(e) => e.stopPropagation()}
 73→            >
 74→                <div className="oe-header">
 75→                    <p className="oe-title">Share your opinion</p>
 76→                    <button className="oe-close-btn" onClick={handleCloseEditor} aria-label="Close editor">
 77→                        <svg xmlns="http://www.w3.org/2000/svg" height="18px" viewBox="0 -960 960 960" width="18px" fill="currentColor"><path d="m256-200-56-56 224-224-224-224 56-56 224 224 224-224 56 56-224 224 224 224-56 56-224-224-224 224Z"></path></svg>
 78→                    </button>
 79→                </div>
 80→
 81→                <div className="oe-body">
 82→                    <textarea
 83→                        ref={opinionTextareaRef}
 84→                        maxLength={280}
 85→                        value={opinion}
 86→                        onChange={(e) => { setOpinion(e.target.value); mentionTextareaProps.onChange(e); }}
 87→                        onKeyDown={mentionTextareaProps.onKeyDown}
 88→                        onKeyUp={mentionTextareaProps.onKeyUp}
 89→                        className="oe-textarea"
 90→                        name="opinions"
 91→                        placeholder="What's on your mind..."
 92→                        rows={5}
 93→                    />
 94→                    <MentionDropdown {...mentionDropdownProps} />
 95→                </div>
 96→
 97→                <div className="oe-footer">
 98→                    <span className={`oe-char-count ${isAtLimit ? 'oe-char-limit' : isNearLimit ? 'oe-char-warn' : ''}`}>
 99→                        {charCount}/280
100→                    </span>
101→
102→                    <button
103→                        onClick={(e) => handleClickSave(e)}
104→                        disabled={!opinion || isSaving}
105→                        className={`oe-save-btn ${!opinion || isSaving ? 'oe-save-disabled' : ''}`}
106→                    >
107→                        {isSaving ? 'Saving...' : 'Post'}
108→                    </button>
109→                </div>
110→
111→                {isSaving && (
112→                    <div className="oe-loader">
113→                        <BarLoader loading={isSaving} width={'100%'} color="var(--accent-sage)" speedMultiplier={0.7}/>
114→                    </div>
115→                )}
116→            </motion.div>
117→        </motion.div>
118→        </AnimatePresence>
119→    )
120→}
121→
122→export default OpinionEditor;

